"use strict";(self.rspackChunkdocs=self.rspackChunkdocs||[]).push([["851"],{43(e,t,n){n.r(t),n.d(t,{default:()=>o});var a=n(4848),r=n(8453);function s(e){return(0,a.jsx)(a.Fragment,{})}function o(){let e=arguments.length>0&&void 0!==arguments[0]?arguments[0]:{},{wrapper:t}={...(0,r.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(s,{...e})}):s(e)}o.__RSPRESS_PAGE_META={},o.__RSPRESS_PAGE_META["index.md"]={toc:[],title:"",headingTitle:"",frontmatter:{pageType:"home",hero:{name:"Tamer4Lynx",text:"Native routing, UI, and platform APIs for Lynx apps",tagline:'<p><strong>Tamer</strong> extends <a href="https://lynxjs.org/" target="_blank" rel="noopener">Lynx</a> with routing, shell UI, and native modules—auth, storage, transports, and more—for <strong>iOS, Android, and web</strong>. <strong>HarmonyOS</strong> support is coming soon. You keep building with Lynx and Rspeedy; <strong>Tamer</strong> handles native hosts, modules, and builds.</p>\n<p><strong>Debug</strong> and <strong>production</strong> builds take a few commands, <strong>native modules</strong> included—you skip the repetitive Xcode and Gradle setup.</p>\n',actions:[{theme:"brand",text:"Getting Started",link:"/guide/getting-started/"},{theme:"alt",text:"Configuration",link:"/guide/configuration"},{theme:"alt",text:"Commands",link:"/reference/commands"},{theme:"alt",text:"GitHub",link:"https://github.com/tamer4lynx/tamer4lynx"}],image:{src:"/tamer-logo.png",alt:"Tamer4Lynx"}},features:[{title:"File-based routing",details:"tamer-router provides Stack and Tabs layouts with AppBar/TabBar, Rsbuild route generation, and system back integration (`tamer-router:back`, `useBackHandler` / `usePreventBack`, native `didHandleBack`).",icon:"🧭"},{title:"Dev client",details:"tamer-dev-client offers QR scan, discovery, URL persistence, recent-server reachability dots, and a reload bridge for the dev launcher experience.",icon:"🔧"},{title:"UI components",details:"tamer-app-shell, tamer-icons, tamer-insets, and tamer-system-ui for native UI building blocks. Text inputs use Lynx built-in `<input>` and `<textarea>`.",icon:"🎨"},{title:"Platform APIs",details:"tamer-transports, tamer-screen, tamer-auth, tamer-secure-store, tamer-biometric, tamer-linking, tamer-display-browser, and tamer-webview.",icon:"📦"},{title:"Lynx Autolink RFC",details:'Aligned with the <a href="https://github.com/lynx-family/lynx/discussions/2653" target="_blank" rel="noopener">Lynx Autolink RFC</a>. Uses lynx.ext.json for extension discovery and linking.',icon:"🔗"},{title:"Cross-platform",details:'Targets iOS, Android, and web from a single codebase with <a href="https://lynxjs.org/react/" target="_blank" rel="noopener">ReactLynx</a> and <a href="https://lynxjs.org/rspeedy/" target="_blank" rel="noopener">Rspeedy</a>. HarmonyOS support coming soon.',icon:"🌍"},{title:"Framework agnostic",details:'Tamer4Lynx is conceptually Lynx framework agnostic and should work with <a href="https://github.com/haskell-miso/miso-lynx" target="_blank" rel="noopener">miso-lynx</a>, <a href="https://github.com/rahul-vashishtha/lynx-stack/tree/lynx-vue-implementation/packages/vue" target="_blank" rel="noopener">VueLynx</a> (@lynx-js/vue), or other Lynx bindings. Some modules like tamer-router are specifically designed for @lynx-js/react.',icon:"⚡"}]}}}}]);